INSERT INTO `v1_acaf60d7cd740103cdef894c86792ba07911d46edf3a15d3fb9a706b278a8afd` VALUES ("", 1030038, "あっ、たしかにそうですね！\nまずは目の前のぴにゃこら太さんに\n認めてもらわなきゃですし♪", "", 3, 11, 10, 1, 1, 112411, "");
